parameters.jsCode:
// 生成 content_id
const now = new Date();
const id = now.toISOString().replace(/[-:T]/g, '').slice(0, 15);

const input = $input.first().json.body;

return [{
  json: {
    content_id: id,
    type: input.type || 'deep-post',
    title: input.title || '未命名内容',
    count: input.count || 1,
    notebook_id: input.notebook_id || 'bd630b56-afb1-478b-aab9-9dba5a762f7d'
  }
}];

